// ─── Normalize & Enrich Jira Trigger Payload ───────────────────────────
const data = $input.first().json;
const issue   = data.issue;
const fields  = issue.fields;
const changelog = data.changelog;

// Fix versions
const fixVersions = (fields.fixVersions || []).map(v => v.name).join(', ') || 'N/A';

// Components
const components = (fields.components || []).map(c => c.name).join(', ') || 'General';

// Labels
const labels = (fields.labels || []).join(', ') || 'None';

// Customer email — falls back to reporter email
const customerEmail =
  fields.customfield_10050 ||
  fields.reporter?.emailAddress ||
  null;

// Customer name
const customerName =
  fields.customfield_10051 ||
  fields.reporter?.displayName ||
  'Valued Customer';

// Resolution comment
const resolutionComment =
  fields.resolution?.description ||
  fields.customfield_10052 ||
  'This issue has been fully resolved by our engineering team.';

// Priority
const priority = fields.priority?.name || 'Medium';

// Find status change from changelog
const statusChange = (changelog?.items || []).find(i => i.field === 'status');
const fromStatus   = statusChange?.fromString || 'Unknown';
const toStatus     = statusChange?.toString   || 'Done';

// Dates
const resolutionDate = new Date().toISOString();
const createdDate    = fields.created || resolutionDate;
const daysOpen = Math.round(
  (new Date(resolutionDate) - new Date(createdDate)) / (1000 * 60 * 60 * 24)
);

// Assignee
const assignee = fields.assignee?.displayName || 'Engineering Team';

// Sprint
const sprints    = fields.customfield_10020 || fields.customfield_10021;
const sprintName = Array.isArray(sprints) && sprints.length > 0
  ? (sprints[sprints.length - 1]?.name || 'Current Sprint')
  : 'N/A';

// Issue URL
const baseUrl  = issue.self.split('/rest')[0];
const issueUrl = `${baseUrl}/browse/${issue.key}`;

return [{
  json: {
    issueKey:         issue.key,
    issueId:          issue.id,
    issueUrl,
    summary:          fields.summary,
    description:      fields.description || 'No description provided.',
    priority,
    components,
    labels,
    fixVersions,
    sprintName,
    assignee,
    reporter:         fields.reporter?.displayName || 'Unknown',
    fromStatus,
    toStatus,
    customerEmail,
    customerName,
    resolutionComment,
    resolutionDate,
    daysOpen,
    createdDate,
    hasCustomerEmail: !!customerEmail
  }
}];

// ─── Deduplication via workflow static data (global scope) ──────────────
const issueKey  = $input.first().json.issueKey;
const storeKey  = `resolved_${issueKey}`;
const store     = $getWorkflowStaticData('global');
const already   = store[storeKey] === true;
if (!already) store[storeKey] = true;
return [{ json: { ...$input.first().json, alreadyProcessed: already } }];

// ─── Get enriched data via node reference ────────────────────────────────
const enriched = $('Has Customer Email?').first().json;

// ─── Get parallel fetch results ──────────────────────────────────────────
const inputs = $input.all().map(i => i.json);

// Jira details response has nested fields.comment
const jiraDetails = inputs.find(i =>
  i.hasOwnProperty('fields') && i.fields?.comment !== undefined
) || {};

// HubSpot response has 'results' array or 'total' property
const hsResult = inputs.find(i =>
  i.hasOwnProperty('results') || i.hasOwnProperty('total')
) || {};

// ── Latest Jira comment ───────────────────────────────────────────────────
const comments = jiraDetails.fields?.comment?.comments || [];
const lastComment = comments.length > 0
  ? (
      comments[comments.length - 1]?.body?.content?.[0]?.content?.[0]?.text ||
      comments[comments.length - 1]?.body ||
      enriched.resolutionComment
    )
  : enriched.resolutionComment;
const safeComment = String(lastComment || 'This issue has been fully resolved.').substring(0, 600);

// ── HubSpot contact ───────────────────────────────────────────────────────
const hsContacts  = Array.isArray(hsResult.results) ? hsResult.results
                  : Array.isArray(hsResult)          ? hsResult
                  : [];
const hsContact   = hsContacts[0] || null;
const hsContactId = hsContact?.id || null;
const hsFirstName = hsContact?.properties?.firstname || (enriched.customerName || '').split(' ')[0] || 'Customer';
const hsLastName  = hsContact?.properties?.lastname  || '';
const hsCompany   = hsContact?.properties?.company   || 'N/A';

// ── Email subject ─────────────────────────────────────────────────────────
const emailSubject = `[RESOLVED] ${enriched.issueKey}: ${enriched.summary}`;

const resolvedDateFormatted = enriched.resolutionDate
  ? new Date(enriched.resolutionDate).toLocaleDateString('en-US', {
      year: 'numeric', month: 'long', day: 'numeric'
    })
  : new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

// ── HTML Email ────────────────────────────────────────────────────────────
const emailHtml = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<style>
  body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;color:#1a1a2e;background:#f4f5f7;margin:0;padding:0}
  .wrap{max-width:620px;margin:36px auto;background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 2px 16px rgba(0,0,0,.09)}
  .hd{background:linear-gradient(135deg,#0052cc 0%,#0747a6 100%);padding:30px 40px}
  .hd h1{color:#fff;margin:0;font-size:22px;font-weight:600}
  .badge{display:inline-block;background:#00875a;color:#fff;font-size:11px;font-weight:700;padding:3px 11px;border-radius:100px;margin-top:8px;letter-spacing:.6px;text-transform:uppercase}
  .bd{padding:30px 40px}
  p{margin:0 0 14px;font-size:15px;line-height:1.6}
  .box{background:#f0f4ff;border-left:4px solid #0052cc;border-radius:4px;padding:14px 18px;margin:18px 0}
  .box h3{margin:0 0 6px;font-size:12px;color:#0052cc;text-transform:uppercase;letter-spacing:.5px}
  .box p{margin:0;font-size:15px;color:#2d3a5a}
  table{width:100%;border-collapse:collapse;margin:18px 0;font-size:14px}
  td{padding:8px 0;border-bottom:1px solid #eef0f6}
  td:first-child{color:#6b7894;width:44%}
  td:last-child{color:#1a1a2e;font-weight:500}
  .res{background:#e8f9f0;border-left:4px solid #00875a;border-radius:4px;padding:14px 18px;margin:18px 0}
  .res h3{margin:0 0 6px;font-size:12px;color:#00875a;text-transform:uppercase;letter-spacing:.5px}
  .res p{margin:0;font-size:15px;color:#1a4731}
  .cta{text-align:center;margin:26px 0 8px}
  .btn{display:inline-block;background:#0052cc;color:#fff;text-decoration:none;padding:12px 28px;border-radius:8px;font-weight:600;font-size:14px}
  .ft{background:#f4f5f7;padding:22px 40px;border-top:1px solid #eef0f6}
  .ft p{color:#8a9bbf;font-size:12px;margin:3px 0}
</style>
</head>
<body>
<div class="wrap">
  <div class="hd"><h1>Bug Fix Resolved</h1><span class="badge">&#10003; Resolved</span></div>
  <div class="bd">
    <p>Hi ${enriched.customerName || 'Valued Customer'},</p>
    <p>We are pleased to confirm that the bug you reported has been <strong>fully resolved</strong>. Here is a summary of what was fixed:</p>
    <div class="box"><h3>Issue Summary</h3><p>${enriched.summary || 'N/A'}</p></div>
    <table>
      <tr><td>Issue Key</td><td><a href="${enriched.issueUrl || '#'}" style="color:#0052cc">${enriched.issueKey || 'N/A'}</a></td></tr>
      <tr><td>Priority</td><td>${enriched.priority || 'N/A'}</td></tr>
      <tr><td>Fix Version</td><td>${enriched.fixVersions || 'N/A'}</td></tr>
      <tr><td>Component</td><td>${enriched.components || 'N/A'}</td></tr>
      <tr><td>Resolved By</td><td>${enriched.assignee || 'Engineering Team'}</td></tr>
      <tr><td>Days to Resolve</td><td>${enriched.daysOpen ?? 'N/A'} ${typeof enriched.daysOpen === 'number' ? (enriched.daysOpen !== 1 ? 'days' : 'day') : ''}</td></tr>
      <tr><td>Resolved On</td><td>${resolvedDateFormatted}</td></tr>
    </table>
    <div class="res"><h3>Resolution Notes</h3><p>${safeComment}</p></div>
    <p>If you experience any related issues or have questions, please do not hesitate to reach out. We truly appreciate your patience.</p>
    <div class="cta"><a href="${enriched.issueUrl || '#'}" class="btn">View Full Issue Details</a></div>
  </div>
  <div class="ft">
    <p>You received this email because you are listed as a contact on Jira issue ${enriched.issueKey || 'N/A'}.</p>
    <p>This is an automated notification from our Engineering Operations system.</p>
  </div>
</div>
</body>
</html>`;

// ── HubSpot note body ─────────────────────────────────────────────────────
const hubspotNoteBody =
`[BUG RESOLVED] ${enriched.issueKey}: ${enriched.summary}

Resolution Date : ${resolvedDateFormatted}
Priority        : ${enriched.priority}
Fix Version     : ${enriched.fixVersions}
Component       : ${enriched.components}
Resolved By     : ${enriched.assignee}
Days Open       : ${enriched.daysOpen}
Sprint          : ${enriched.sprintName}

Resolution Notes:
${safeComment}

Jira Link: ${enriched.issueUrl}`;

return [{
  json: {
    ...enriched,
    lastComment: safeComment,
    hsContactId,
    hsFirstName,
    hsLastName,
    hsCompany,
    hsContactFound: !!hsContactId,
    emailSubject,
    emailHtml,
    hubspotNoteBody,
    resolvedDateFormatted
  }
}];

