// No customer email on this Jira issue — flag for manual follow-up
const data = $input.first().json;
console.warn(`[NO EMAIL] Issue ${data.issueKey} resolved but no customer email found.`);
return [{ json: { ...data, requiresManualFollowUp: true, warningReason: 'No customer email on Jira issue' } }];

